      { angle: "When Faithfulness Looks Foolish", target_audience: "Those pressured to give up on difficult relationships or callings", primary_theme: "countercultural love" },
      { angle: "Spiritual Adultery in an Age of Distraction", target_audience: "General congregation", primary_theme: "modern idolatry and divided loyalties" }
